import{_ as t,o as r,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"云海香炉","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/云海香炉 .md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/云海香炉 .md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/云海香炉 .md"};function d(_,a,l,i,c,h){return r(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"云海香炉",tabindex:"-1"},[n("云海香炉 "),e("a",{class:"header-anchor",href:"#云海香炉","aria-label":'Permalink to "云海香炉"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="云海香炉-1" tabindex="-1">云海香炉 <a class="header-anchor" href="#云海香炉-1" aria-label="Permalink to &quot;云海香炉&quot;">​</a></h1><p>云海香炉</p><p>D+500</p><p>奇物（腰带位）</p><p>【外观】<br> 一个巴掌大的旧香炉，由某种温润的乳白色石材制成，表面有细密的自然海纹。形状像个小碗，带着一个刻有简单云纹的盖子，缕缕让人心神宁静的青烟从盖子的缝隙中缓缓飘出。</p><p>【效果】</p><p>[安眠]· 当你进行长休时，香炉将会自行点燃特制的药尘，能有效的屏蔽风雨、异味、蚊虫等常见干扰，让携带者即使在野外，也能睡个好觉，视为自适应长休</p><p>[静心]· 位于非长休状态时，该香炉将会自行缩小，化为腰间的挂物，缕缕清神静心的云烟将会为你打散那些扰人的杂念，佩戴者的意志豁免获得2点增强加值</p><p>[香尘]·游云望海，历经世事万千，积累在炉中的香尘，让青烟开始带有异香，每当携带者进入一个世界，都可以寻找当界的植物进行焚香，当前世界结束后，香炉将会根据携带者所投入的植物，自行的在炉身上铭刻相对应的花纹，皆此之后，香炉提供的意志豁免加值，将会提升3点。</p><p>注：本物带来的一切效果，仅有携带/佩戴时，才可生效</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=t(o,[["render",d]]);export{b as __pageData,m as default};
